import React, { useState, useEffect } from "react";
import Header from "../components/Header";
import Sidebar from "../components/Sidebar";
import Toolbar from "../components/Toolbar";
import MessageList from "../components/MessageList";
import { DashboardProps, Menu, MessageItem } from "../types";
import { useFetch } from "../hooks/useFetch";
import { getMenus, getItems } from "../services/api";

/**
 * Componente principal Dashboard da aplicação
 * Gerencia o estado principal da aplicação após o login
 * 
 * @param onLogout - Função callback para realizar logout
 */
const Dashboard = ({ onLogout }: DashboardProps) => {
  // Estado para armazenar os menus principais da aplicação
  const [menus, setMenus] = useState<Menu[]>([]);
  
  // Estado para armazenar os itens/mensagens do menu selecionado
  const [items, setItems] = useState<MessageItem[]>([]);
  
  // Estado para controlar quais itens estão selecionados (para ações em lote)
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  
  // Estado para controlar qual submenu está selecionado atualmente
  const [selectedSubMenuId, setSelectedSubMenuId] = useState<number | null>(null);

  // Hook customizado para buscar os menus da API
  const { data: menusData, loading: menusLoading, error: menusError } = useFetch(
    () => getMenus(),
    [] // Array de dependências vazio para executar apenas uma vez
  );

  // Hook customizado para buscar itens do submenu selecionado
  const { data: itemsData, loading: itemsLoading, error: itemsError } = useFetch(
    () => selectedSubMenuId ? getItems(selectedSubMenuId) : Promise.resolve([]),
    [selectedSubMenuId] // Executa quando o submenu selecionado muda
  );

  // Efeito para atualizar o estado dos menus quando os dados da API mudam
  useEffect(() => {
    if (menusData) {
      setMenus(menusData);
    }
  }, [menusData]);

  // Efeito para atualizar o estado dos itens quando os dados da API mudam
  useEffect(() => {
    if (itemsData) {
      setItems(itemsData);
    }
  }, [itemsData]);

  /**
   * Função para arquivar os itens selecionados
   * Implementação básica que remove os itens selecionados da lista
   */
  const handleArchive = () => {
    setItems((prevItems: MessageItem[]) => 
      prevItems.filter((item: MessageItem) => !selectedIds.includes(item.id))
    );
    setSelectedIds([]); // Limpa a seleção após arquivar
  };

  // Exibe mensagem de carregamento enquanto os menus são carregados
  if (menusLoading) {
    return (
      <div className="h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Carregando menus...</p>
        </div>
      </div>
    );
  }

  // Exibe mensagem de erro se ocorrer erro ao carregar menus
  if (menusError) {
    return (
      <div className="h-screen flex items-center justify-center">
        <div className="text-center text-red-600">
          <p>Erro ao carregar menus: {(menusError as Error).message}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex bg-white">
      {/* Sidebar com navegação principal */}
      <Sidebar 
        menus={menus}
        onSelect={setSelectedSubMenuId}
      />

      {/* Conteúdo principal da aplicação */}
      <div className="flex-1 flex flex-col">
        {/* Header com informações do usuário e logout */}
        <Header onLogout={onLogout} />

        {/* Toolbar com ações para itens selecionados */}
        <Toolbar 
          selectedIds={selectedIds}
          onArchive={handleArchive}
        />

        {/* Lista de mensagens/itens */}
        <div className="flex-1 overflow-auto">
          {itemsLoading ? (
            <div className="flex items-center justify-center h-full">
              <div className="text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600 mx-auto"></div>
                <p className="mt-2 text-gray-600">Carregando itens...</p>
              </div>
            </div>
          ) : itemsError ? (
            <div className="flex items-center justify-center h-full">
              <div className="text-center text-red-600">
                <p>Erro ao carregar itens: {(itemsError as Error).message}</p>
              </div>
            </div>
          ) : (
            <MessageList 
              items={items}
              selectedIds={selectedIds}
              setSelectedIds={setSelectedIds}
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
